SEARCH_ORDERS_SCHEMA = {
    "type": "object",
    "properties": {
        "status": {
            "type": "string",
            "enum": ["pending", "processing", "shipped", "delivered", "cancelled"],
            "description": "Filter by order status.",
        },
        "customer_email": {
            "type": "string",
            "format": "email",
            "maxLength": 254,
            "description": "Filter by customer email address.",
        },
        "date_from": {
            "type": "string",
            "pattern": "^\\d{4}-\\d{2}-\\d{2}$",
            "description": "Earliest order date, YYYY-MM-DD.",
        },
        "limit": {
            "type": "integer",
            "minimum": 1,
            "maximum": 100,
            "default": 20,
        },
    },
    "additionalProperties": False,
}

from pydantic import BaseModel, EmailStr, Field, field_validator
from typing import Any, Literal
import re

class SearchOrdersInput(BaseModel):
    status: Literal["pending","processing","shipped","delivered","cancelled"] | None = None
    customer_email: EmailStr | None = None
    date_from: str | None = None
    limit: int = Field(default=20, ge=1, le=100)

    @field_validator("date_from")
    @classmethod
    def validate_date(cls, v: str | None) -> str | None:
        if v is None:
            return v
        if not re.fullmatch(r"\d{4}-\d{2}-\d{2}", v):
            raise ValueError("date_from must be YYYY-MM-DD")
        year, month, day = map(int, v.split("-"))
        if not (1 <= month <= 12 and 1 <= day <= 31):
            raise ValueError("date_from contains an invalid month or day")
        return v

def search_orders(**kwargs: Any) -> dict[str, Any]:
    try:
        params = SearchOrdersInput(**kwargs)
    except ValueError as exc:
        # Pydantic raises ValueError; extract the first error message
        errors = exc.errors() if hasattr(exc, "errors") else [{"msg": str(exc)}]
        return {
            "error": "VALIDATION_ERROR",
            "message": errors[0]["msg"],
            "field": errors[0].get("loc", [None])[0],
        }
    # params is now fully validated
    return _do_search(params)

import re
from pathlib import Path
from urllib.parse import urlparse

# Shell metacharacter injection guard
_SHELL_META = re.compile(r'[;&|$`<>(){}\\]')

def reject_shell_injection(value: str, field: str) -> dict | None:
    if _SHELL_META.search(value):
        return {"error": "VALIDATION_ERROR",
                "message": f"{field} contains disallowed shell characters"}
    return None

# Path traversal guard
def reject_path_traversal(path_str: str, sandbox: Path) -> dict | None:
    try:
        resolved = Path(path_str).resolve()
        resolved.relative_to(sandbox)  # raises ValueError if outside
    except (ValueError, OSError):
        return {"error": "VALIDATION_ERROR",
                "message": "Path is outside the permitted sandbox"}
    return None

# SSRF guard — block private/internal network targets
_PRIVATE = re.compile(
    r'^(localhost|127\.|10\.|192\.168\.|172\.(1[6-9]|2\d|3[01])\.)'
)

def reject_ssrf(url: str) -> dict | None:
    parsed = urlparse(url)
    if parsed.scheme not in ("http", "https"):
        return {"error": "VALIDATION_ERROR",
                "message": "URL scheme must be http or https"}
    host = parsed.hostname or ""
    if _PRIVATE.match(host):
        return {"error": "VALIDATION_ERROR",
                "message": "Requests to private network addresses are not permitted"}
    return None

# Prompt injection marker guard
_INJECTION_MARKERS = [
    "ignore previous instructions",
    "disregard your system prompt",
    "you are now",
    "act as",
    "jailbreak",
]

def warn_prompt_injection(text: str) -> bool:
    """Return True if the text contains common injection patterns."""
    lower = text.lower()
    return any(marker in lower for marker in _INJECTION_MARKERS)

