def export_orders(
    date_from: str,
    date_to: str,
    format: str = "csv",
    limit: int = 1000,
) -> dict[str, Any]:
    # Cross-field: date range must be valid
    if date_from > date_to:
        return {
            "error": "VALIDATION_ERROR",
            "message": "date_from must be on or before date_to",
            "field": "date_from",
        }

    # Cross-field: very large exports require a format that supports streaming
    if limit > 500 and format == "json":
        return {
            "error": "VALIDATION_ERROR",
            "message": "JSON format is limited to 500 records; use csv for larger exports",
            "field": "format",
        }

    # Cross-field: date range must not exceed 90 days (prevents runaway queries)
    from datetime import date
    d_from = date.fromisoformat(date_from)
    d_to   = date.fromisoformat(date_to)
    if (d_to - d_from).days > 90:
        return {
            "error": "VALIDATION_ERROR",
            "message": "Date range must not exceed 90 days",
            "field": "date_to",
        }

    return _run_export(date_from, date_to, format, limit)
